// ClaudeHydra Service Worker — Workbox CDN strategy
// This file lives in /public and is served as-is (no build step).
// Precache manifest (sw-manifest.json) is generated by swManifestPlugin in vite.config.ts.
/* eslint-disable no-restricted-globals */

importScripts('https://storage.googleapis.com/workbox-cdn/releases/7.3.0/workbox-sw.js');

workbox.setConfig({ debug: false });

const { precacheAndRoute, cleanupOutdatedCaches } = workbox.precaching;
const { registerRoute } = workbox.routing;
const { CacheFirst, NetworkFirst, StaleWhileRevalidate } = workbox.strategies;
const { ExpirationPlugin } = workbox.expiration;
const { CacheableResponsePlugin } = workbox.cacheableResponse;

// ── Precaching ──────────────────────────────────────────────────────────
// Load the manifest generated at build time, then precache listed assets.
fetch('/sw-manifest.json')
  .then(function (resp) {
    if (!resp.ok) throw new Error('No manifest');
    return resp.json();
  })
  .then(function (entries) {
    if (entries && entries.length > 0) {
      precacheAndRoute(entries);
    }
  })
  .catch(function () {
    // No manifest available (dev mode or first deploy) — skip precaching
  });

cleanupOutdatedCaches();

// ── Runtime caching: WASM binaries (Cache-First, long TTL) ─────────────
registerRoute(
  function (ctx) { return ctx.url.pathname.startsWith('/wasm/'); },
  new CacheFirst({
    cacheName: 'wasm-cache',
    plugins: [
      new CacheableResponsePlugin({ statuses: [0, 200] }),
      new ExpirationPlugin({
        maxEntries: 10,
        maxAgeSeconds: 60 * 60 * 24 * 90, // 90 days
      }),
    ],
  }),
);

// ── Runtime caching: Static assets — JS/CSS chunks (Cache-First) ───────
registerRoute(
  function (ctx) { return ctx.url.pathname.startsWith('/assets/') && /\.(js|css)$/.test(ctx.url.pathname); },
  new CacheFirst({
    cacheName: 'static-assets',
    plugins: [
      new CacheableResponsePlugin({ statuses: [0, 200] }),
      new ExpirationPlugin({
        maxEntries: 100,
        maxAgeSeconds: 60 * 60 * 24 * 30, // 30 days
      }),
    ],
  }),
);

// ── Runtime caching: Images & fonts (StaleWhileRevalidate) ─────────────
registerRoute(
  function (ctx) { return /\.(webp|png|jpg|jpeg|svg|ico|woff2?)$/.test(ctx.url.pathname); },
  new StaleWhileRevalidate({
    cacheName: 'images-fonts',
    plugins: [
      new CacheableResponsePlugin({ statuses: [0, 200] }),
      new ExpirationPlugin({
        maxEntries: 50,
        maxAgeSeconds: 60 * 60 * 24 * 30, // 30 days
      }),
    ],
  }),
);

// ── Runtime caching: Google Fonts (Cache-First, 1 year) ────────────────
registerRoute(
  function (ctx) {
    return ctx.url.origin === 'https://fonts.googleapis.com' || ctx.url.origin === 'https://fonts.gstatic.com';
  },
  new CacheFirst({
    cacheName: 'google-fonts',
    plugins: [
      new CacheableResponsePlugin({ statuses: [0, 200] }),
      new ExpirationPlugin({
        maxEntries: 20,
        maxAgeSeconds: 60 * 60 * 24 * 365, // 1 year
      }),
    ],
  }),
);

// ── Runtime caching: API responses (Network-First, short TTL) ──────────
registerRoute(
  function (ctx) { return ctx.url.pathname.startsWith('/api/'); },
  new NetworkFirst({
    cacheName: 'api-cache',
    networkTimeoutSeconds: 5,
    plugins: [
      new CacheableResponsePlugin({ statuses: [0, 200] }),
      new ExpirationPlugin({
        maxEntries: 50,
        maxAgeSeconds: 60 * 5, // 5 minutes
      }),
    ],
  }),
);

// ── Navigation fallback (SPA) ──────────────────────────────────────────
// For navigation requests, try network first then fall back to cached index.html.
registerRoute(
  function (ctx) { return ctx.request.mode === 'navigate'; },
  new NetworkFirst({
    cacheName: 'navigation-cache',
    networkTimeoutSeconds: 3,
    plugins: [
      new CacheableResponsePlugin({ statuses: [0, 200] }),
    ],
  }),
);

// ── Skip waiting & claim clients immediately ───────────────────────────
self.addEventListener('message', function (event) {
  if (event.data && event.data.type === 'SKIP_WAITING') {
    self.skipWaiting();
  }
});

self.addEventListener('activate', function (event) {
  event.waitUntil(self.clients.claim());
});
